VALUES
  ('cpa-moex-01551', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行土地稅法規定，有關我國地價稅之敘述，下列何者正確？', '["採累進稅率，最高稅率為50‰", "按每一土地所有權人在每一直轄市或縣（市）轄區內之地價總額計徵", "累進起點地價，以各該直轄市及縣（市）土地10公畝之平均地價為準", "計算累進起點地價，不包括自用住宅用地、工廠用地、礦業用地、農業用地及免稅土地在內"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01552', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '現行稅捐稽徵法有關稅捐核課期間之起算規定，下列敘述何者正確？', '["依法應由納稅義務人申報繳納之稅捐，已在規定期間內申報者，自申報日起算", "依法應由納稅義務人申報繳納之稅捐，未在規定期間內申報繳納者，自規定申報期間屆滿之日起算", "印花稅自依法應貼用印花稅票翌日起算", "由稅捐稽徵機關按稅籍底冊或查得資料核定徵收之稅捐，自該稅捐所屬徵期屆滿之日起算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01553', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '王先生於100年7月1日向李先生購買一筆土地，並於同年9月25日完成產權登記，依現行土地稅相關 法規規定，該筆土地100年度地價稅之納稅義務人原則上是誰？', '["王先生", "李先生", "1月1日至6月30日為李先生，7月1日至12月31日為王先生", "1月1日至9月24日為李先生，9月25日至12月31日為王先生"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01554', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行稅捐稽徵法規定，納稅義務人應納稅捐在下列何種情況下，應由稅捐稽徵機關移送法院強制執行？', '["已依規定申請復查者", "於繳納期間屆滿30日後仍未繳納者", "納稅義務人對復查決定之應納稅額繳納半數，並依法提起訴願者", "繳納半數稅額確有困難，經稽徵機關核准，提供相當擔保者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01555', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行稅捐稽徵法規定，納稅義務人欠繳應納營業稅時，若能提供相當財產擔保，則可免被稅捐稽徵機關 聲請法院就其財產實施假扣押。下列何者不符合相當擔保之規定？', '["累積留抵稅額", "黃金", "公債", "機器設備"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01556', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '根據現行遺產及贈與稅法，下列那一項金額不適用每遇消費者物價指數較上次調整之指數累計上漲達 10%以上時，自次年起按上漲程度調整的規定？', '["被繼承人日常生活必需之器具及用具、職業上之工具，不計入遺產總額之金額", "被繼承人之配偶、直系血親卑親屬、父母、兄弟姊妹、祖父母扣除額、喪葬費扣除額及殘障特別扣除額", "免稅額", "父母於子女婚嫁時所贈與之財物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01557', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行遺產及贈與稅法規定，有關不計入贈與總額、不計入遺產總額或扣除額的敘述，下列何者正確？', '["遺贈人、受遺贈人或繼承人捐贈依法登記為財團法人組織且符合行政院規定標準之教育、文化、公益、 慈善、宗教團體及祭祀公業之財產不計入遺產總額", "遺產中作農業使用之農業用地及其地上農作物，由繼承人或受遺贈人承受者，扣除其土地及地上農作 物價值之全數。承受人自承受之日起 5 年內，未將該土地繼續作農業使用且未在有關機關所令期限內 恢復作農業使用，或雖在有關機關所令期限內已恢復作農業使用而再有未作農業使用情事者，應追繳 半數應納稅賦", "作農業使用之農業用地及其地上農作物，贈與民法第1138條及1140條所定繼承人者，不計入其土地 及地上農作物價值之全數。受贈人自受贈之日起 5 年內，未將該土地繼續作農業使用且未在有關機關 所令期限內恢復作農業使用，或雖在有關機關所令期限內已恢復作農業使用而再有未作農業使用情事 者，應追繳應納稅賦", "捐贈依法登記為財團法人組織且符合行政院規定標準之教育、文化、公益、慈善、宗教團體及祭祀公業 之財產不計入贈與總額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01558', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行遺產及贈與稅法規定，被繼承人死亡前幾年內，繼承之財產已納遺產稅者，全數不計入遺產總額 課徵遺產稅？', '["5年", "6年", "7年", "9年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01559', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '陳凱只有美國國籍，但在臺灣已經居留數十年，偶爾往返美國。陳凱常在美國舉債而後將資金轉入臺灣 投資。最近陳凱死亡，陳凱之繼承人已在美國申報及繳納遺產稅。有關陳凱之遺產在我國遺產稅之課徵， 依遺產及贈與稅相關法規規定，下列敘述何者正確？', '["中華民國境內境外全部遺產均應課徵遺產稅", "在美國繳納的遺產稅可以扣抵中華民國境內應納之遺產稅", "美國的負債可以扣除中華民國境內之遺產", "僅就其在中華民國境內之遺產課徵遺產稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01560', 'cpa', 'cpa-moex-102-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依現行遺產及贈與稅相關法規規定，有關配偶剩餘財產差額分配請求權在遺產稅的敘述，下列何者錯誤？', '["配偶拋棄繼承權時，仍可主張剩餘財產差額分配請求權之價值自被繼承人遺產總額中扣除", "死亡前2年內贈與配偶之財產應併入遺產總額課徵遺產稅，惟不得列入剩餘財產差額分配請求權範圍", "納稅義務人未於稽徵機關核發稅款繳清證明書或免稅證明書之日起 1 年內，給付該請求權金額之財產 予被繼承人之配偶者，稽徵機關應於前述期間屆滿之翌日起5年內，就未給付部分追繳應納稅賦", "核算剩餘財產差額分配請求權之價值時，不計入遺產總額之捐贈財產、政府開闢或無償提供公眾通行 之道路土地、公共設施保留地及農業用地等，因已不計入遺產總額課徵遺產稅，不應列入計算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3a357f38dae7", "answer_pdf_sha1": "b0996baf9a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01561', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '年專門職業及技術人員高等考試律師、 代號：80330 會計師、不動產估價師、專利師考試試題 類    科：會計師 甲、申論題部分：（50分） 不必抄題，作答時請將試題題號及答案依照順序寫在申論試卷上，於本試題上作答者，不予計分。 請以藍、黑色鋼筆或原子筆在申論試卷上作答。', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 102, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01562', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '劍橋公司收購取得四季公司全部股權，四季公司隨即消滅，收購過程中產生商譽$1,200,000，而四季 公司原有一商標權，公允價值為$200,000，然劍橋公司未來並不打算使用該商標權，則該商標權在收 購日之入帳金額為何？', '["$0", "$200,000", "$200,000，並立即全額轉列損失", "附註揭露取得一商標權，待將來使用該商標權再以當時公允價值入帳"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01563', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司收購乙公司75%股權、丙公司82%股權，然收購日對乙公司非控制權益以該非控制權益公允 價值衡量，而對丙公司非控制權益則以該非控制權益依比例所享有之被收購者可辨認淨資產衡量。 這樣的作法：', '["對乙、丙公司之非控制權益均應以該非控制權益之公允價值衡量", "對乙、丙公司之非控制權益均應以此二家公司可辨認淨資產帳面金額衡量", "對乙、丙公司之非控制權益均應以此二家公司可辨認淨資產公允價值比例衡量", "符合國際財務報導準則之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01564', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '紫薇公司於X5年分二次取得翠竹公司股權，第一次於1月1日以$600,000取得翠竹公司60%股權， 當時翠竹公司權益為$800,000，並依非控制權益之公允價值$400,000衡量非控制權益；第二次於 10月1日以$290,000取得20%股權。X5年初翠竹公司除未入帳專利權$100,000外，其他可辨認資產、 負債之帳面金額均與公允價值相等，該專利權分十年攤銷。翠竹公司X5年淨利為$600,000，係於一年 中平均賺得，且於7月1日宣告並發放股利$80,000。紫薇公司採用權益法處理對翠竹公司之投資， X5年10月1日紫薇公司取得20%之股權後，下列敘述何者正確？', '["「投資翠竹公司」帳戶餘額增加$290,000", "投資收益增加$195,000", "資本公積減少$17,500", "非控制權益減少$200,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01565', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '承上題，紫薇公司與翠竹公司X5年度合併損益表之專利權攤銷費用為何？', '["$10,000", "$8,000", "$6,500", "$0"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01566', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '楚楚公司及其持股80%之子公司翰和公司X2年的個別淨利分別為$1,000,000及$850,000。楚楚公司 將商品以成本的120%價格出售給翰和公司。楚楚公司於X1年及X2年銷貨予翰和公司的金額分別 為$3,400,000 及$3,600,000。截至 X1 年底及 X2 年底，翰和公司帳上購自楚楚公司的商品中分別有 $720,000及$480,000尚未出售。X2年楚楚公司及翰和公司之合併淨利為何？', '["$720,000", "$1,712,000", "$1,720,000", "$1,850,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01567', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '大華公司於X1年將帳面金額$18,000的土地，以$21,000的價格出售予其持股80%的小利公司。直至 X5年時，小利公司方以$22,000的價格將該土地出售予第三者。此一公司間交易將使：', '["大華公司X1年之投資收益減少$3,000，但使X5年之投資收益增加$3,000", "大華公司X1年之投資收益增加$3,000，但使X5年之投資收益減少$3,000", "大華公司X1年之投資收益增加$3,000，但使X5年之投資收益減少$2,000", "大華公司X1年之投資收益減少$2,400，但使X5年之投資收益增加$1,600"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01568', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', 'X1年1月1日大樑公司的長期負債包含面額$900,000、利率10%、X5年1月1日到期的應付公司債， 未攤銷溢價$48,000，付息日為1月1日及7月1日，採直線法攤銷。大樑公司持有小叮公司80%的 股權。X1年1月2日，小叮公司以$612,000的價格從債券市場中，購買大樑公司流通在外面額$600,000 的債券。大樑公司及小叮公司X1年度合併綜合損益表上，債券的推定贖回損益為何？', '["利得$20,000", "利得$36,000", "損失$8,000", "損失$20,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01569', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '承上題，大樑公司及小叮公司X2年12月31日合併資產負債表上，大樑公司的應付公司債加上未攤 銷溢價後的餘額應為：', '["$300,000", "$308,000", "$312,000", "$316,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01570', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司持有乙公司 60%股權。本年度甲公司出售存貨給乙公司，銷貨毛利至年底尚未實現之金額為 $100,000。乙公司去年亦曾銷貨給甲公司，至本年度方實現的毛利金額為$80,000。所得稅稅率為25%。 試問：本年度合併遞延所得稅資產有何變化？', '["增加$13,000", "減少$13,000", "增加$5,000", "減少$5,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01571', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', 'X1年初臺北公司持有臺中公司80%股權，臺中公司持有臺南公司90%股權。當年不含投資收益之個 別淨利分別為：臺北公司$420,000；臺中公司$280,000；臺南公司$280,000。假設取得時各投資之移 轉對價均等於被投資公司可辨認淨資產公允價值比例，且被投資公司各項可辨認資產及負債之公允 價值均與帳面金額相當。前述臺南公司之淨利包含了出售給臺中公司商品之未實現毛利$56,000。X1 年 度控制權益淨利為何？', '["$706,670", "$755,980", "$805,280", "$815,770"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01572', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '母公司直接從子公司現金增資購買新股以增加持股比例，合併現金流量表應如何表達？', '["列於營業活動項下", "列於投資活動項下", "列於籌資活動項下", "無須於合併現金流量表中表達"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01573', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', 'X1 年初臺北公司以$240,000 取得臺中公司 60%股權，採權益法處理該投資，當日臺中公司之權益 $200,000，包括普通股股本$80,000（每股面額$10）及保留盈餘$120,000，且除設備低估外，並無其 他未攤銷差額，該設備尚可使用十年，採用直線法折舊。臺中公司X6年初的保留盈餘為$175,000， 上半年獲利$25,000。臺北公司於X6年7月1日以$300,000出售其對臺中公司之所有持股，試問出 售損益金額為何？', '["$12,000", "$60,000", "$78,000", "$87,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01574', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '母公司取得子公司特別股時，若所支付對價之公允價值低於子公司該部分特別股於合併報表之帳面 金額，有關該差額之敘述，下列何者正確？', '["減少合併保留盈餘", "增加合併淨利", "增加資本公積", "減少特別股投資成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01575', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '臺北公司於X1年初以$360,000購入臺中公司60%股權，採權益法處理該項投資，並依非控制權益之 公允價值$240,000衡量非控制權益，當日臺中公司之權益$450,000。臺北公司於X4年初以$200,000 另自非控制權益股東取得臺中公司20%股權，當時臺中公司權益為$700,000，係保留盈餘增加所致。 兩次取得股權時，臺中公司各項可辨認資產及負債帳面金額均等於公允價值。X4年底合併報表列示 之商譽為何？', '["$0", "$60,000", "$100,000", "$150,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
